import React from 'react'
import { CFooter } from '@coreui/react'

const AppFooter = () => {
  return (
    <CFooter>
      <div>        
        <span className="ms-1">&copy; 2023 <a href="https://wseinfratech.com/" target="_blank" rel="noopener noreferrer">WSE INFRATECH PVT LTD</a>.</span>
      </div>
      <div className="ms-auto">
        <span className="me-1">Powered by</span>
        <a href="https://wseinfratech.com/" target="_blank" rel="noopener noreferrer">WSE INFRATECH PVT LTD &amp; Dashboard</a>
      </div>
    </CFooter>
  )
}

export default React.memo(AppFooter)
